	#include<iostream>

	using namespace std;

	void f(int a, int b, int c)

	{

		cout << a << b << c << ‘/’;

		if(a == 3 && b == 2 && c == 1)

			return;

		if(b < c)

			f(a, c, b);

		else if(a < b)

		{

			if(a < c)

				f(c, a, b);

			else

				f(b, c, a);

		}

	}

	int main()

	{

		int a, b, c;

		cin >> a >> b >> c;

		f(a, b, c);

		cout << endl;

		return 0;

	}
