### 代码

```
	#include <iostream>

	#include <cstring>

	using namespace std;

	int i,j,len;

	char s[50];

	int main()

	{

		cin >>s;

		len = strlen(s);

		for (i = 0;i < len; ++i)

		{

			if (s[i] >= 'A' && s[i] <= 'Z') s[i] -= 'A' - 'a';

		}

		for (i = 0;i < len; ++i)

		{

			if (s[i] < 'x') s[i] += 3; else s[i] += -23;

		}

		cout << s << '/';

		for (j = 1;j < 4;j ++)

		{

			for (i = 0;i < len-j; i = i + j)

			{

				s[i] = s[i + j] ;

			}

		}

		cout << s << endl;

		return 0;

	}
```

